import {
  ChangeDetectionStrategy,
  Component,
  signal,
} from '@angular/core';
import { FormsModule } from '@angular/forms';
import { ServiceConfig } from '../core/models';

@Component({
  selector: 'app-admin-settings',
  standalone: true,
  changeDetection: ChangeDetectionStrategy.OnPush,
  imports: [FormsModule],
  templateUrl: './admin-settings.component.html',
  styleUrl: './admin-settings.component.css',
})
export class AdminSettingsComponent {
  /**
   * DATA CONTRACT: backend-provided service configuration. Declared as a typed
   * signal of mock objects so mockup_cleaner/service_agent can wire it to the
   * settings API.
   */
  readonly services = signal<ServiceConfig[]>([
    {
      key: 'postgresql',
      label: 'PostgreSQL',
      description: 'Primary store for stations, observations & climate normals.',
      configured: true,
      fields: [
        { key: 'host', label: 'Host', type: 'text', placeholder: 'db.internal', value: 'pg.weather-2.internal' },
        { key: 'port', label: 'Port', type: 'number', placeholder: '5432', value: '5432' },
        { key: 'database', label: 'Database', type: 'text', placeholder: 'weather', value: 'weather_prod' },
        { key: 'username', label: 'Username', type: 'text', placeholder: 'app', value: 'weather_app' },
        { key: 'password', label: 'Password', type: 'password', placeholder: '••••••••', value: 'storedsecret' },
      ],
    },
    {
      key: 'redis',
      label: 'Redis',
      description: 'Frame cache for computed interpolation results.',
      configured: false,
      fields: [
        { key: 'host', label: 'Host', type: 'text', placeholder: 'cache.internal', value: '' },
        { key: 'port', label: 'Port', type: 'number', placeholder: '6379', value: '' },
        { key: 'password', label: 'Password', type: 'password', placeholder: '••••••••', value: '' },
      ],
    },
  ]);

  /** Per-service transient "saved" confirmation. */
  readonly savedKey = signal<string | null>(null);

  updateField(serviceKey: string, fieldKey: string, value: string): void {
    this.services.update((list) =>
      list.map((s) =>
        s.key !== serviceKey
          ? s
          : {
              ...s,
              fields: s.fields.map((f) =>
                f.key === fieldKey ? { ...f, value } : f,
              ),
            },
      ),
    );
  }

  save(serviceKey: string): void {
    // Mock persist: mark configured when all fields have a value.
    this.services.update((list) =>
      list.map((s) =>
        s.key !== serviceKey
          ? s
          : { ...s, configured: s.fields.every((f) => f.value.trim() !== '') },
      ),
    );
    this.savedKey.set(serviceKey);
  }
}
